-- get_边_标签
-- Helper function: Get 标签 from 边 by 边Id
-- Used for join-free cross-table references in aggregations
CREATE OR REPLACE FUNCTION get_边_标签(p_边id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT 标签 FROM 边 WHERE 边id = p_边id);
$$ LANGUAGE sql STABLE;

