-- calc_形状_边的类型
-- Field: 形状.边的类型
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_形状_边的类型(p_形状id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_形状_边的数量(p_形状id))::text = (0)::text THEN '空' WHEN (calc_形状_边的数量(p_形状id))::text = (1)::text THEN '点' WHEN (calc_形状_边的数量(p_形状id))::text = (2)::text THEN '线' WHEN (calc_形状_边的数量(p_形状id))::text = (3)::text THEN '三角形' WHEN (calc_形状_边的数量(p_形状id))::text = (4)::text THEN '正方形' ELSE '--' END)::text;
$$ LANGUAGE sql STABLE;

