-- calc_形状_勾股定理成立
-- Field: 形状.勾股定理成立
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_形状_勾股定理成立(p_形状id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_形状_边的数量(p_形状id))::NUMERIC = 3 THEN (calc_形状_非斜边角度总和(p_形状id) = (COALESCE(CASE WHEN (calc_形状_最大边长(p_形状id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_形状_最大边长(p_形状id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN (calc_形状_最大边长(p_形状id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_形状_最大边长(p_形状id))::numeric ELSE NULL END, 0)))::text ELSE (NULL)::text END)::text;
$$ LANGUAGE sql STABLE;

