-- calc_边_长度平方
-- Field: 边.长度平方
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_边_长度平方(p_边id TEXT)
RETURNS TEXT AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT 长度 FROM 边 WHERE 边id = p_边id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT 长度 FROM 边 WHERE 边id = p_边id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((SELECT 长度 FROM 边 WHERE 边id = p_边id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT 长度 FROM 边 WHERE 边id = p_边id))::numeric ELSE NULL END, 0)))::text;
$$ LANGUAGE sql STABLE;

