-- calc_形状_edges
-- Field: 形状.Edges
-- Type: Many-side relationship (backref) to 边
-- Aggregates: 边.边Id where 形状 = parent
CREATE OR REPLACE FUNCTION calc_形状_edges(p_形状id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(边id::TEXT, ', ' ORDER BY 边id)
    FROM 边
    WHERE 形状 = p_形状id
  );
$$ LANGUAGE sql STABLE;

